import{_ as t,c as e,o as s,U as o}from"./chunks/framework.NGyteOZM.js";const b=JSON.parse('{"title":"站点说明","description":"","frontmatter":{"title":"站点说明","next":false,"lastUpdated":false},"headers":[],"relativePath":"pages/index.md","filePath":"pages/index.md","lastUpdated":1705480578000}'),r={name:"pages/index.md"},n=o('<div class="danger custom-block"><p class="custom-block-title">重要事情说三遍：仅供参考！仅供参考！仅供参考！</p><p><strong>目的：作为前端工程师，具备开发多个前端平台（PC、移动WEB、APP、桌面、小程序等）以及自主开发服务端的完整技术解决方案的能力，并能够进行相关项目管理。（大前端，轻后端，懂管理）</strong></p><p>为了以上的目的，按照个人的理解，站内技术按照以下规则进行分类：</p><ol><li><p><strong>了解（Awareness）：</strong> 在这个级别，你对技术有一些基本的了解和认识，你知道它的存在以及一些基本概念和术语。你可能能够理解技术的一般思想或原理，但对于具体的实施细节可能知之甚少。</p></li><li><p><strong>熟悉（Familiarity）：</strong> 在这个级别，你对技术有更深入的了解。你可能已经接触过该技术的一些具体应用，能够描述其主要特点和用途。你对技术的基本工作原理和相关概念有一定的了解，但在实践中可能需要借助其他资源或指导。</p></li><li><p><strong>掌握（Proficiency）：</strong> 在这个级别，你已经具备了较高水平的技术能力。你可以独立地应用该技术解决问题，并能够理解和解释其复杂的概念和原理。你对技术的实践经验丰富，能够灵活运用，并具备解决相关问题的能力。</p></li><li><p><strong>精通（Mastery）：</strong> 在这个级别，你是该技术领域的专家。你对技术有极其深入的理解和广泛的实践经验。你能够解决复杂的问题，深度优化和创新技术应用。你对技术的掌握程度超越了大多数人，可能在该领域有卓越的贡献，并能够培养和指导其他人。</p></li></ol></div><div class="warning custom-block"><p class="custom-block-title">重申首页内容</p><p><strong>阅读须知 🪧</strong></p><p>网站内容均为个人总结或收集，仅供参考。部分内容使用AI生成或来源网络，如有侵权请联系我删除。</p><p><strong>更新说明 🚀</strong></p><p>随缘更新，如发现网站中的错误，欢迎到<a href="https://github.com/kobelhn/kobelhn.github.io" target="_blank" rel="noreferrer">GitHub</a>提交issue帮助我改正。</p><p><strong>点个星星 ⭐</strong></p><p>创建此网站主要是为了方便自己查阅，如果能帮助到你，欢迎到<a href="https://github.com/kobelhn/kobelhn.github.io" target="_blank" rel="noreferrer">GitHub</a>给我一个小小的star。</p></div>',2),a=[n];function i(p,l,c,_,g,d){return s(),e("div",null,a)}const m=t(r,[["render",i]]);export{b as __pageData,m as default};
